// Calls: productService.calculateFinalRequiredComponents(productId, qty, customizations)
// Calls: stockService.getAvailableStock(componentId) for each component
const { calculateFinalRequiredComponents } = require('./app/js/customizations/customizationService.js');
const { getAvailableStock } = require('./app/js/stock/stockService.js');
const { orderId, productId, quantity, customizations } = $input.first().json;
const required = calculateFinalRequiredComponents(productId, quantity, customizations || []);
const stockCheck = required.required_components.map(c => ({
  ...c,
  available: getAvailableStock(c.component_id),
  missing: Math.max(0, c.required_qty - getAvailableStock(c.component_id))
}));
return [{ json: { orderId, stockCheck, hasShortage: stockCheck.some(c => c.missing > 0) } }];

// Calls: purchaseService.createOrMergePurchaseRequest(missingComponents)
// Merges with existing Draft/Pending requests for same components
const { createOrMergePurchaseRequest } = require('./app/js/purchases/purchaseService.js');
const missing = $json.stockCheck.filter(c => c.missing > 0);
const pr = createOrMergePurchaseRequest(missing);
return [{ json: { ...$json, purchaseRequest: pr } }];

// Calls: stockService.reserveStock(orderId, requiredComponents)
// Updates Stock.reserved_qty, creates Reservations + InventoryTransactions
const { reserveStock } = require('./app/js/stock/stockService.js');
const result = reserveStock($json.orderId, $json.stockCheck);
return [{ json: { ...$json, reservationResult: result } }];

const { updateOrderStatus } = require('./app/js/orders/orderService.js');
const status = $json.hasShortage ? 'WaitingPurchase' : 'ProposalSent';
updateOrderStatus($json.orderId, status);
return [{ json: { ...$json, newStatus: status } }];
